#ifndef GEMM_N5120_K2048_KERNEL_H_
#define GEMM_N5120_K2048_KERNEL_H_

#include <cuda_runtime.h>
#include <cuda_fp16.h>

#ifdef __cplusplus
extern "C" {
#endif

// C = A * B^T
// A: [M, 2048] fp16 row-major
// B: [5120, 2048] fp16 row-major
// C: [M, 5120] fp16 row-major
void gemm_n5120_k2048_launch(const half* A, const half* B, half* C, int M, cudaStream_t stream);

#ifdef __cplusplus
} // extern "C"
#endif

#endif // GEMM_N5120_K2048_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cstdio>
#include <cstdint>

#define CUDA_CHECK_HOST(expr) do {                                      \
  cudaError_t _err = (expr);                                            \
  if (_err != cudaSuccess) {                                            \
    fprintf(stderr, "CUDA error %s at %s:%d\n",                         \
            cudaGetErrorString(_err), __FILE__, __LINE__);              \
  }                                                                     \
} while (0)

static constexpr int N_CONST = 5120;
static constexpr int K_CONST = 2048;

// Threadblock tile
static constexpr int BM = 16;     // rows of C per block
static constexpr int BN = 128;    // cols of C per block
static constexpr int BK = 32;     // K per stage (must divide 2048)

static_assert((K_CONST % BK) == 0, "K must be divisible by BK");
static_assert((N_CONST % BN) == 0, "N must be divisible by BN");

// 256 threads/block: 32x8
// - x: 0..31
// - y: 0..7
// Each thread computes 2 rows (m offsets: y and y+8) and 4 cols (n offsets: x*4..x*4+3)
struct __align__(16) Smem {
  half sA[BM][BK];        // 16x32 = 512 half
  half sB[BK][BN + 1];    // 32x129 to reduce bank conflicts
};

__device__ __forceinline__ void mma2_acc(float &acc, half2 a2, half2 b2) {
  // FP16 multiply accumulate in FP32 (2-lane)
  const float2 af = {__half2float(__low2half(a2)), __half2float(__high2half(a2))};
  const float2 bf = {__half2float(__low2half(b2)), __half2float(__high2half(b2))};
  acc = fmaf(af.x, bf.x, acc);
  acc = fmaf(af.y, bf.y, acc);
}

extern "C" __global__ void gemm_n5120_k2048_kernel(const half* __restrict__ A,
                                                  const half* __restrict__ B,
                                                  half* __restrict__ C,
                                                  int M) {
  __shared__ Smem smem;

  const int tx = (int)threadIdx.x; // 0..31
  const int ty = (int)threadIdx.y; // 0..7
  const int tid = ty * 32 + tx;    // 0..255

  const int m0 = (int)blockIdx.y * BM;
  const int n0 = (int)blockIdx.x * BN;

  // Thread's output coordinates
  const int n_lane = tx * 4;           // 0..124
  const int m_a = m0 + ty;             // first row
  const int m_b = m0 + ty + 8;         // second row

  float acc_a0 = 0.f, acc_a1 = 0.f, acc_a2 = 0.f, acc_a3 = 0.f;
  float acc_b0 = 0.f, acc_b1 = 0.f, acc_b2 = 0.f, acc_b3 = 0.f;

#pragma unroll 1
  for (int k0 = 0; k0 < K_CONST; k0 += BK) {
    // Load A tile: BM*BK = 512 half -> 2 per thread (256 threads)
#pragma unroll
    for (int i = 0; i < 2; ++i) {
      const int linear = tid + i * 256;   // 0..511
      const int ar = linear / BK;         // 0..15
      const int ac = linear - ar * BK;    // 0..31
      const int gm = m0 + ar;
      half v = __float2half(0.f);
      if (gm < M) {
        v = A[(size_t)gm * K_CONST + (k0 + ac)];
      }
      smem.sA[ar][ac] = v;
    }

    // Load B tile: BK*BN = 4096 half -> 16 per thread (256 threads)
#pragma unroll
    for (int i = 0; i < 16; ++i) {
      const int linear = tid + i * 256;    // 0..4095
      const int bk = linear / BN;          // 0..31
      const int bn = linear - bk * BN;     // 0..127
      // B is [N,K] row-major, access B[n, k]
      smem.sB[bk][bn] = B[(size_t)(n0 + bn) * K_CONST + (k0 + bk)];
    }

    __syncthreads();

    // Compute: for two rows
    const bool in_a = (m_a < M);
    const bool in_b = (m_b < M);

#pragma unroll
    for (int kk = 0; kk < BK; kk += 2) {
      // A half2 for row a and b
      half2 a2a = *reinterpret_cast<const half2*>(&smem.sA[ty + 0][kk]);
      half2 a2b = *reinterpret_cast<const half2*>(&smem.sA[ty + 8][kk]);

      const int nb = n_lane;
      // Build half2 from two consecutive k elements for each output column
      half2 b20 = __halves2half2(smem.sB[kk + 0][nb + 0], smem.sB[kk + 1][nb + 0]);
      half2 b21 = __halves2half2(smem.sB[kk + 0][nb + 1], smem.sB[kk + 1][nb + 1]);
      half2 b22 = __halves2half2(smem.sB[kk + 0][nb + 2], smem.sB[kk + 1][nb + 2]);
      half2 b23 = __halves2half2(smem.sB[kk + 0][nb + 3], smem.sB[kk + 1][nb + 3]);

      if (in_a) {
        mma2_acc(acc_a0, a2a, b20);
        mma2_acc(acc_a1, a2a, b21);
        mma2_acc(acc_a2, a2a, b22);
        mma2_acc(acc_a3, a2a, b23);
      }
      if (in_b) {
        mma2_acc(acc_b0, a2b, b20);
        mma2_acc(acc_b1, a2b, b21);
        mma2_acc(acc_b2, a2b, b22);
        mma2_acc(acc_b3, a2b, b23);
      }
    }

    __syncthreads();
  }

  // Store results
  const int nbase = n0 + n_lane;

  if (m_a < M) {
    half* out = C + (size_t)m_a * N_CONST + nbase;
    out[0] = __float2half_rn(acc_a0);
    out[1] = __float2half_rn(acc_a1);
    out[2] = __float2half_rn(acc_a2);
    out[3] = __float2half_rn(acc_a3);
  }
  if (m_b < M) {
    half* out = C + (size_t)m_b * N_CONST + nbase;
    out[0] = __float2half_rn(acc_b0);
    out[1] = __float2half_rn(acc_b1);
    out[2] = __float2half_rn(acc_b2);
    out[3] = __float2half_rn(acc_b3);
  }
}

void gemm_n5120_k2048_launch(const half* A, const half* B, half* C, int M, cudaStream_t stream) {
  if (M <= 0) return;

  dim3 block(32, 8, 1); // 256 threads
  dim3 grid(N_CONST / BN, (M + BM - 1) / BM, 1);

  gemm_n5120_k2048_kernel<<<grid, block, 0, stream>>>(A, B, C, M);
  CUDA_CHECK_HOST(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include "kernel.h"

static void check_2d_fp16_cuda_contig(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.device().is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.dtype() == torch::kFloat16, name, " must be float16");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
  TORCH_CHECK(t.dim() == 2, name, " must be 2D");
}

// Signature must stay: run(A, B, out=None)
torch::Tensor run(torch::Tensor A, torch::Tensor B, torch::optional<torch::Tensor> out = torch::nullopt) {
  check_2d_fp16_cuda_contig(A, "A");
  check_2d_fp16_cuda_contig(B, "B");

  const int64_t M64 = A.size(0);
  const int64_t K64 = A.size(1);
  TORCH_CHECK(K64 == 2048, "A.shape[1] must be 2048, got ", K64);
  TORCH_CHECK(B.size(0) == 5120, "B.shape[0] must be 5120, got ", B.size(0));
  TORCH_CHECK(B.size(1) == 2048, "B.shape[1] must be 2048, got ", B.size(1));
  TORCH_CHECK(M64 >= 0 && M64 <= INT32_MAX, "M out of supported range, got ", M64);
  const int M = (int)M64;

  torch::Tensor C;
  if (out.has_value() && out.value().defined()) {
    C = out.value();
    check_2d_fp16_cuda_contig(C, "out");
    TORCH_CHECK(C.size(0) == M64 && C.size(1) == 5120, "out must have shape [M,5120], got ", C.sizes());
  } else {
    C = torch::empty({M64, 5120}, A.options());
  }

  const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr<at::Half>());
  const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr<at::Half>());
  half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();
  gemm_n5120_k2048_launch(A_ptr, B_ptr, C_ptr, M, stream);

  cudaError_t err = cudaGetLastError();
  TORCH_CHECK(err == cudaSuccess, "CUDA kernel launch failed: ", cudaGetErrorString(err));

  return C;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gemm_n5120_k2048 (CUDA)", py::arg("A"), py::arg("B"), py::arg("out") = py::none());
}
